    13→export async function verifySession(req?: NextRequest): Promise<SessionUser | null> {
    14→  try {
    15→    const cookieStore = await cookies()
    16→    const supabase = createServerClient(
    17→      process.env.NEXT_PUBLIC_SUPABASE_URL!,
    18→      process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
    19→      {
    20→        cookies: {
    21→          getAll() {
    22→            return cookieStore.getAll()
    23→          },
    24→          setAll(cookiesToSet) {
    25→            try {
    26→              cookiesToSet.forEach(({ name, value, options }) =>
    27→                cookieStore.set(name, value, options)
    28→              )
    29→            } catch {}
    30→          },
    31→        },
    32→      }
    33→    )
    34→
    35→    const { data: { user }, error } = await supabase.auth.getUser()
    36→    if (error || !user) return null
    37→
    38→    let dbUser = await prisma.user.findUnique({ where: { id: user.id } })
    39→    if (!dbUser) {
    40→      dbUser = await prisma.user.create({
    41→        data: { id: user.id, email: user.email!, role: "OWNER" },
    42→      })
    43→    }
    44→
    45→    return { userId: dbUser.id, email: dbUser.email, role: dbUser.role }
    46→  } catch {
    47→    return null
    48→  }
    49→}
