    56→export function requireRole(session: SessionUser, role: UserRole): SessionUser {
    57→  const hierarchy: Record<UserRole, number> = { OWNER: 3, COLLABORATOR: 2, VIEWER: 1 }
    58→  if (hierarchy[session.role] < hierarchy[role]) throw new Error("FORBIDDEN")
    59→  return session
    60→}
