    82→function applyWhere(query: any, where: Record<string, any>): any {
    83→  for (const [key, value] of Object.entries(where)) {
    84→    if (value === undefined) continue
    85→    if (value === null) {
    86→      query = query.is(key, null)
    87→    } else if (typeof value === "object" && !Array.isArray(value)) {
    88→      if ("notIn" in value) {
    89→        query = query.not(key, "in", `(${(value.notIn as string[]).join(",")})`)
    90→      } else if ("in" in value) {
    91→        query = query.in(key, value.in as string[])
    92→      } else if ("gte" in value) {
    93→        query = query.gte(key, value.gte)
    94→      } else if ("lte" in value) {
    95→        query = query.lte(key, value.lte)
    96→      } else if ("gt" in value) {
    97→        query = query.gt(key, value.gt)
    98→      } else if ("lt" in value) {
    99→        query = query.lt(key, value.lt)
   100→      } else if ("contains" in value) {
   101→        query = query.ilike(key, `%${value.contains}%`)
   102→      }
   103→    } else {
   104→      query = query.eq(key, value)
   105→    }
   106→  }
   107→  return query
   108→}
