   110→async function resolveIncludes(
   111→  tableName: string,
   112→  record: Record<string, unknown>,
   113→  include: Record<string, IncludeSpec>
   114→): Promise<Record<string, unknown>> {
   115→  if (!record) return record
   116→  const result: Record<string, unknown> = { ...record }
   117→  const tableRelations = RELATIONS[tableName] ?? {}
   118→
   119→  for (const [key, spec] of Object.entries(include)) {
   120→    if (key === "_count") {
   121→      result._count = {}
   122→      const countSpec = (spec as { select?: Record<string, boolean> }).select ?? {}
   123→      for (const countKey of Object.keys(countSpec)) {
   124→        const rel = tableRelations[countKey]
   125→        if (!rel || rel.type === "belongsTo") {
   126→          ;(result._count as Record<string, number>)[countKey] = 0
   127→          continue
   128→        }
   129→        const { count } = await supabaseAdmin
   130→          .from(rel.table)
   131→          .select("*", { count: "exact", head: true })
   132→          .eq(rel.fk, record.id as string)
   133→        ;(result._count as Record<string, number>)[countKey] = count ?? 0
   134→      }
   135→      continue
   136→    }
   137→
   138→    const rel = tableRelations[key]
   139→    if (!rel) continue
   140→
   141→    const nestedInclude =
   142→      spec !== true ? (spec as { include?: Record<string, IncludeSpec> }).include : undefined
   143→
   144→    if (rel.type === "belongsTo") {
   145→      const fkValue = record[rel.selfFk ?? rel.fk]
   146→      if (!fkValue) {
   147→        result[key] = null
   148→        continue
   149→      }
   150→      const { data } = await supabaseAdmin.from(rel.table).select("*").eq("id", fkValue as string).maybeSingle()
   151→      result[key] =
   152→        nestedInclude && data
   153→          ? await resolveIncludes(rel.table, data as Record<string, unknown>, nestedInclude)
   154→          : data
   155→    } else if (rel.type === "hasOne") {
   156→      const { data } = await supabaseAdmin
   157→        .from(rel.table)
   158→        .select("*")
   159→        .eq(rel.fk, record.id as string)
   160→        .maybeSingle()
   161→      result[key] =
   162→        nestedInclude && data
   163→          ? await resolveIncludes(rel.table, data as Record<string, unknown>, nestedInclude)
   164→          : data
   165→    } else {
   166→      let q = supabaseAdmin.from(rel.table).select("*").eq(rel.fk, record.id as string)
   167→      if (spec !== true) {
   168→        const s = spec as {
   169→          where?: Record<string, unknown>
   170→          orderBy?: Record<string, "asc" | "desc">
   171→          take?: number
   172→        }
   173→        if (s.where) q = applyWhere(q, s.where)
   174→        if (s.orderBy) {
   175→          const [ok, ov] = Object.entries(s.orderBy)[0]
   176→          q = q.order(ok, { ascending: ov === "asc" })
   177→        }
   178→        if (s.take) q = q.limit(s.take)
   179→      }
   180→      const { data } = await q
   181→      const items = (data ?? []) as Record<string, unknown>[]
   182→      result[key] = nestedInclude
   183→        ? await Promise.all(items.map((item) => resolveIncludes(rel.table, item, nestedInclude)))
   184→        : items
   185→    }
   186→  }
   187→
   188→  return result
   189→}
