   209→    orderBy?: Record<string, "asc" | "desc">
   210→  }): Promise<any> {
   211→    let q = supabaseAdmin.from(this.tableName).select("*")
   212→    q = applyWhere(q, args.where)
   213→    if (args.orderBy) {
