   232→    if (args?.orderBy) {
   233→      const [ok, ov] = Object.entries(args.orderBy)[0]
   234→      q = q.order(ok, { ascending: ov === "asc" })
   235→    }
   236→    if (args?.take) q = q.limit(args.take)
   237→    const { data } = await q
   238→    const items = (data ?? []) as any[]
   239→    if (args?.include) {
   240→      return Promise.all(items.map((item) => resolveIncludes(this.tableName, item, args.include!)))
   241→    }
   242→    return items
