   244→
   245→  // eslint-disable-next-line @typescript-eslint/no-explicit-any
   246→  async create(args: { data: Record<string, any> }): Promise<any> {
   247→    const data: Record<string, any> = { id: newId(), ...args.data }
   248→    if (TABLES_WITH_UPDATED_AT.has(this.tableName)) {
   249→      data.updatedAt = new Date().toISOString()
   250→    }
   251→    const { data: created, error } = await supabaseAdmin
   252→      .from(this.tableName)
   253→      .insert(data)
   254→      .select()
   255→      .single()
   256→    if (error) throw new Error(`DB create error on ${this.tableName}: ${error.message}`)
   257→    return created
   258→  }
   259→
   260→  // eslint-disable-next-line @typescript-eslint/no-explicit-any
   261→  async createMany(args: { data: Record<string, any>[] }): Promise<{ count: number }> {
   262→    const rows = args.data.map((d) => ({ id: newId(), ...d }))
   263→    const { error } = await supabaseAdmin.from(this.tableName).insert(rows)
   264→    if (error) throw new Error(`DB createMany error on ${this.tableName}: ${error.message}`)
   265→    return { count: rows.length }
   266→  }
   267→
   268→  // eslint-disable-next-line @typescript-eslint/no-explicit-any
   269→  async update(args: { where: Record<string, any>; data: Record<string, any> }): Promise<any> {
   270→    const updateData: Record<string, any> = { ...args.data }
   271→    if (TABLES_WITH_UPDATED_AT.has(this.tableName)) {
   272→      updateData.updatedAt = new Date().toISOString()
   273→    }
   274→    let q = supabaseAdmin.from(this.tableName).update(updateData)
   275→    q = applyWhere(q, args.where)
   276→    const { data, error } = await q.select().single()
   277→    if (error) throw new Error(`DB update error on ${this.tableName}: ${error.message}`)
   278→    return data
   279→  }
   280→
   281→  // eslint-disable-next-line @typescript-eslint/no-explicit-any
   282→  async upsert(args: {
   283→    where: Record<string, any>
   284→    create: Record<string, any>
   285→    update: Record<string, any>
   286→  }): Promise<any> {
   287→    const existing = await this.findUnique({ where: args.where })
   288→    if (existing) {
   289→      return this.update({ where: args.where, data: args.update })
   290→    }
   291→    return this.create({ data: { ...args.where, ...args.create } })
   292→  }
   293→
   294→  // eslint-disable-next-line @typescript-eslint/no-explicit-any
   295→  async delete(args: { where: Record<string, any> }): Promise<any> {
   296→    let q = supabaseAdmin.from(this.tableName).delete()
   297→    q = applyWhere(q, args.where)
   298→    const { data } = await q.select().maybeSingle()
   299→    return data
   300→  }
   301→
   302→  // eslint-disable-next-line @typescript-eslint/no-explicit-any
   303→  async deleteMany(args: { where: Record<string, any> }): Promise<{ count: number }> {
   304→    let q = supabaseAdmin.from(this.tableName).delete()
   305→    q = applyWhere(q, args.where)
   306→    await q
   307→    return { count: 0 }
