     4→export async function validateBody<T>(
     5→  schema: ZodSchema<T>,
     6→  req: NextRequest
     7→): Promise<{ data: T } | { error: NextResponse }> {
     8→  try {
     9→    const body = await req.json()
    10→    const result = schema.safeParse(body)
    11→    if (!result.success) {
    12→      return {
    13→        error: NextResponse.json(
    14→          { error: "Validation error", details: result.error.flatten().fieldErrors },
    15→          { status: 400 }
    16→        ),
    17→      }
    18→    }
    19→    return { data: result.data }
    20→  } catch {
    21→    return {
    22→      error: NextResponse.json({ error: "Invalid JSON body" }, { status: 400 }),
    23→    }
    24→  }
    25→}
